import { Component, h, Host, Prop } from '@stencil/core';
import { generateRandId } from '../../../utils/utils';

@Component({
  tag: 'wdpr-chip-menu-group',
  styleUrl: 'wdpr-chip-menu-group.css',
  scoped: true,
})
export class WdprChipMenuGroup {
  private _internalId: string;

  @Prop() header: string;

  componentWillLoad() {
    this._internalId = `wdpr-chip-menu-group-${generateRandId()}`;
  }

  render() {
    return (
      <Host>
        {this.header && (
          <span class="chip-menu-header" id={`${this._internalId}-header`}>
            {this.header}
          </span>
        )}
        <div class="chip-menu-group" role="group" aria-labelledby={this.header ? `${this._internalId}-header` : undefined}>
          <slot />
        </div>
      </Host>
    );
  }
}
